-- Hlíðarkaup accounting — CHART OF ACCOUNTS (bókhaldslyklar)
-- Generated from the store's standard Icelandic chart (230 accounts).
-- Apply after 003_seed.sql.
set search_path = acc, public;


-- best-effort vat_code link (refine per accountant)
update acc.accounts set vat_code = 'S24' where vat_rate = 24 and statement='rekstur' and account_type='tekjur';
update acc.accounts set vat_code = 'S11' where vat_rate = 11 and statement='rekstur' and account_type='tekjur';
update acc.accounts set vat_code = 'I24' where vat_rate = 24 and account_type in ('gjold','eign');
update acc.accounts set vat_code = 'I11' where vat_rate = 11 and account_type in ('gjold','eign');
